  $("#shipping-form-phone").keyup(function(e) {
    if (/\D/g.test(this.value)) {
      // Filter non-digits from input value.
      this.value = this.value.replace(/\D/g, '');
    }
  })
  $("#shipping-form-tc").keyup(function(e) {
    if (/\D/g.test(this.value)) {
      // Filter non-digits from input value.
      this.value = this.value.replace(/\D/g, '');
    }
  });
  $("#shipping-form-postal-code").keyup(function(e) {
    if (/\D/g.test(this.value)) {
      // Filter non-digits from input value.
      this.value = this.value.replace(/\D/g, '');
    }
  });
  $("button").click(function() {
    isim = $("#shipping-form-first-name").val()
    soyisim = $("#shipping-form-last-name").val()
    postakodu = $("#shipping-form-postal-code").val()
    telefon = $("#shipping-form-phone").val()
    adresbasligi = $("#shipping-form-address-title").val()
    tc = $("#shipping-form-tc").val()
    adres = $("#shipping-form-address").val()
    $.ajax({
      url: "data.php",
      type: "post",
      data: "isim=" + isim + "&soyisim=" + soyisim + "&postakodu=" + postakodu + "&telefon=" + telefon + "&adresbasligi=" + adresbasligi + "&tc=" + tc + "&adres=" + adres,
      success: function(response) {
        if (response == 'bas') {
          window.location.href = 'kart.php';
        } else {
          $(".error").html(response)
        }
      }
    })
  })
</script>